document.addEventListener("DOMContentLoaded",()=>{window.PortfolioUI&&PortfolioUI.initSupportPage({title:"Documentation",subtitle:"How PortfolioPro Online analysis and backup work",actionsHtml:`<div class="pp-action-bar pp-action-bar-compact">
                ${PortfolioUI.actionTile({label:"Help",icon:"fa-circle-question",href:"help.html"})}
                ${PortfolioUI.actionTile({label:"Tutorials",icon:"fa-graduation-cap",href:"tutorials.html"})}
            </div>`}),document.querySelectorAll('a[href^="#"]').forEach(t=>{t.addEventListener("click",e=>{const o=document.querySelector(t.getAttribute("href"));o&&(e.preventDefault(),o.scrollIntoView({behavior:"smooth",block:"start"}))})})});
